const productos=$('Parsear Input').first().json.productos||[];const token=$vars.CT_TOKEN;const allResults=[];
for(const p of productos){
  try{
    const resp=await $helpers.httpRequest({method:'GET',url:'https://api.ctonline.mx/catalogo',headers:{Authorization:`Bearer ${token}`,'Content-Type':'application/json'},qs:{q:p.searchQuery,limit:5}});
    const items=resp.productos||resp.data||[];
    for(const item of (Array.isArray(items)?items:[]).slice(0,3)){
      allResults.push({mayorista:'CT Internacional',sku:item.clave||item.id||'',skuFabricante:item.numero_parte||'',descripcion:item.nombre||item.descripcion||'',marca:item.marca||p.marca,precio:Number(item.precio||0),moneda:'MXN',existencia:Number(item.existencia||0),disponible:(item.existencia||0)>0,imagenUrl:item.imagen||'',productoBuscado:p.searchQuery});
    }
  }catch(e){allResults.push({mayorista:'CT Internacional',error:e.message,productoBuscado:p.searchQuery});}
}
return allResults.map(r=>({json:r}));
